#include <stdio.h>
#define MOD 1000000009
int main() {
    int K;
    scanf("%d", &K);
    int N = 1 << K;
    long long dp[N][K + 1];
    for (int i = 0; i < N; i++) {
        dp[i][0] = 1;
    }
    for (int i = 1; i <= K; i++) {
        for (int j = 0; j < N; j++) {
            if (j % (1 << i) < (1 << (i - 1))) {
                dp[j][i] = (dp[j][i - 1] + dp[j + (1 << (i - 1))][i - 1]) % MOD;
            } else {
                dp[j][i] = dp[j - (1 << (i - 1))][i - 1];
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%lld\n", dp[i][K]);
    }
    return 0;
}

